  "consult.birthInfo": { en: "Your Birth Information", ko: "출생 정보", ja: "生年月日情報", es: "Tu información de nacimiento", fr: "Tes informations de naissance", pt: "Suas informações de nascimento", "zh-TW": "你的出生資訊", ru: "Твоя информация о рождении", hi: "तुम्हारी जन्म जानकारी", id: "Informasi Lahirmu" },
