  "compat.title2": { en: "Compatibility", ko: "궁합", ja: "相性", es: "Cósmica", fr: "cosmique", pt: "cósmica", "zh-TW": "合盤", ru: "совместимость", hi: "अनुकूलता", id: "Kosmik" },
  "compat.desc": { en: "Discover how your Four Pillars align with another person's destiny.", ko: "당신의 사주가 상대방의 운명과 어떻게 조화되는지 알아보세요.", ja: "あなたの四柱が相手の運命とどう調和するか確認しましょう。", es: "Descubre cómo tus Cuatro Pilares se alinean con el destino de otra persona.", fr: "Découvre comment tes Quatre Piliers s'alignent avec le destin d'une autre personne.", pt: "Descubra como seus Quatro Pilares se alinham com o destino de outra pessoa.", "zh-TW": "發現你的四柱如何與另一人的命運對應。", ru: "Узнай, как твои Четыре Столпа выравниваются с судьбой другого человека.", hi: "खोजो कि तुम्हारे चार स्तंभ दूसरे व्यक्ति की नियति के साथ कैसे जुड़ते हैं।", id: "Temukan bagaimana Empat Pilarmu sejajar dengan takdir orang lain." },
  "compat.generatedAt": { en: "Generated", ko: "생성일시", ja: "作成日時", es: "Generado", fr: "Généré", pt: "Gerado", "zh-TW": "產生於", ru: "Сгенерировано", hi: "उत्पन्न", id: "Dihasilkan" },
