  "compat.next": { en: "Next: Partner's Info", ko: "다음: 상대방 정보", ja: "次：相手の情報", es: "Siguiente: Info de la pareja", fr: "Suivant : Infos du partenaire", pt: "Próximo: Info do parceiro", "zh-TW": "下一步：伴侶資訊", ru: "Далее: Инфо о партнёре", hi: "अगला: साथी की जानकारी", id: "Berikutnya: Info Pasangan" },
