  "compat.samePerson": { en: "Looks like you entered the same person twice. Try entering a different partner!", ko: "같은 사람을 두 번 입력한 것 같습니다. 다른 상대방을 입력해주세요!", ja: "同じ人を2回入力したようです。別の相手を入力してください！", es: "Parece que ingresaste a la misma persona dos veces. ¡Intenta con una pareja diferente!", fr: "On dirait que tu as entré la même personne deux fois. Essaie avec un autre partenaire !", pt: "Parece que você inseriu a mesma pessoa duas vezes. Tente com um parceiro diferente!", "zh-TW": "看起來你輸入了相同的人兩次。試試不同的伴侶吧！", ru: "Похоже, ты ввёл одного и того же человека дважды. Попробуй с другим партнёром!", hi: "लगता है तुमने एक ही व्यक्ति को दो बार दर्ज किया। एक अलग साथी के साथ कोशिश करो!", id: "Sepertinya kamu memasukkan orang yang sama dua kali. Coba dengan pasangan berbeda!" },
  "compat.stayOnPage": { en: "Please stay on this page — leaving may interrupt the reading.", ko: "이 페이지에 머물러주세요 — 떠나면 분석이 중단될 수 있습니다.", ja: "このページにとどまってください — 離脱すると中断される場合があります。", es: "Por favor permanece en esta página — salir puede interrumpir la lectura.", fr: "Reste sur cette page s'il te plaît — quitter peut interrompre la lecture.", pt: "Por favor permaneça nesta página — sair pode interromper a leitura.", "zh-TW": "請停留在此頁面 — 離開可能中斷解讀。", ru: "Пожалуйста, оставайся на этой странице — уход может прервать чтение.", hi: "कृपया इस पेज पर रहो — छोड़ने से रीडिंग बाधित हो सकती है।", id: "Mohon tetap di halaman ini — meninggalkannya bisa mengganggu bacaan." },
  "compat.readingStars": { en: "Reading the Stars", ko: "별을 읽는 중", ja: "星を読んでいます", es: "Leyendo las estrellas", fr: "Lecture des étoiles", pt: "Lendo as estrelas", "zh-TW": "解讀星辰", ru: "Читаем звёзды", hi: "तारे पढ़ रहे हैं", id: "Membaca Bintang" },
  "compat.craftingPair": { en: "Crafting a reading unique to this pair — about 15 seconds", ko: "이 쌍에 맞는 분석 작성 중 — 약 15초", ja: "このペアの鑑定を作成中 — 約15秒", es: "Creando una lectura única para esta pareja — unos 15 segundos", fr: "Création d'une lecture unique pour ce couple — environ 15 secondes", pt: "Criando uma leitura única para este par — cerca de 15 segundos", "zh-TW": "為這對伴侶打造獨特解讀 — 約15秒", ru: "Создание уникального чтения для этой пары — около 15 секунд", hi: "इस जोड़े के लिए अनोखी रीडिंग बना रहे हैं — लगभग 15 सेकंड", id: "Membuat bacaan unik untuk pasangan ini — sekitar 15 detik" },
