  "cr.startFree": { en: "Start free, upgrade when ready", ko: "무료로 시작, 준비되면 업그레이드", ja: "無料で始めて、準備ができたら", es: "Empieza gratis, actualiza cuando estés listo", fr: "Commence gratuitement, passe à la version supérieure quand tu es prêt", pt: "Comece grátis, atualize quando estiver pronto", "zh-TW": "免費開始，準備好時再升級", ru: "Начни бесплатно, перейди когда будешь готов", hi: "मुफ़्त शुरू करो, तैयार होने पर अपग्रेड करो", id: "Mulai gratis, upgrade saat siap" },
