  "blog.readyToSeeChart": { en: "Ready to see your chart?", ko: "내 사주를 확인할 준비가 되셨나요?", ja: "あなたの命式を確認する準備はできましたか？", es: "¿Listo para ver tu carta?", fr: "Prêt à voir ta carte ?", pt: "Pronto para ver seu mapa?", "zh-TW": "準備好看你的命盤了嗎？", ru: "Готов посмотреть свою карту?", hi: "अपनी कुंडली देखने को तैयार हो?", id: "Siap melihat peta-mu?" },
  "blog.getFreeReading": { en: "Get your free Four Pillars reading in 30 seconds.", ko: "30초 만에 무료 사주 분석을 받아보세요.", ja: "30秒で無料の四柱推命鑑定を受けましょう。", es: "Obtén tu lectura gratis de los Cuatro Pilares en 30 segundos.", fr: "Obtiens ta lecture gratuite des Quatre Piliers en 30 secondes.", pt: "Obtenha sua leitura grátis dos Quatro Pilares em 30 segundos.", "zh-TW": "30秒內取得你免費的四柱命盤。", ru: "Получи бесплатное чтение Четырёх Столпов за 30 секунд.", hi: "30 सेकंड में अपनी मुफ़्त चार स्तंभ रीडिंग पाओ।", id: "Dapatkan bacaan Empat Pilar gratismu dalam 30 detik." },
  "blog.getMyFreeReading": { en: "Get My Free Reading", ko: "무료 사주 보기", ja: "無料で鑑定する", es: "Obtener mi lectura gratis", fr: "Obtenir ma lecture gratuite", pt: "Obter minha leitura grátis", "zh-TW": "取得我的免費命盤", ru: "Получить бесплатное чтение", hi: "मेरी मुफ़्त रीडिंग पाओ", id: "Dapatkan Bacaan Gratis Saya" },
