  // ─── Not Found Page ───
  "notFound.title": { en: "Lost in the Cosmos?", ko: "우주에서 길을 잃으셨나요?", ja: "宇宙で迷子になりましたか？", es: "¿Perdido en el cosmos?", fr: "Perdu dans le cosmos ?", pt: "Perdido no cosmos?", "zh-TW": "迷失於宇宙？", ru: "Потерялся в космосе?", hi: "ब्रह्मांड में खो गए?", id: "Tersesat di Kosmos?" },
  "notFound.desc": { en: "The path you seek doesn't exist in this dimension. Perhaps the stars have redirected you for a reason.", ko: "찾으시는 페이지가 이 차원에 존재하지 않습니다. 별이 당신을 다른 곳으로 인도한 이유가 있을 겁니다.", ja: "お探しのページはこの次元に存在しません。星があなたを導いた理由があるかもしれません。", es: "El camino que buscas no existe en esta dimensión. Tal vez las estrellas te hayan redirigido por una razón.", fr: "Le chemin que tu cherches n'existe pas dans cette dimension. Peut-être que les étoiles t'ont redirigé pour une raison.", pt: "O caminho que você busca não existe nesta dimensão. Talvez as estrelas tenham te redirecionado por um motivo.", "zh-TW": "你尋找的道路不存在於這個次元。或許星辰將你重新導向是有原因的。", ru: "Путь, который ты ищешь, не существует в этом измерении. Возможно, звёзды перенаправили тебя по причине.", hi: "जो रास्ता तुम खोज रहे हो वह इस आयाम में मौजूद नहीं है। शायद तारों ने किसी कारण से तुम्हें पुनर्निर्देशित किया है।", id: "Jalan yang kamu cari tidak ada di dimensi ini. Mungkin bintang-bintang mengarahkanmu kembali karena suatu alasan." },
  "notFound.returnHome": { en: "Return to Earth", ko: "홈으로 돌아가기", ja: "ホームに戻る", es: "Volver a la Tierra", fr: "Retour sur Terre", pt: "Voltar à Terra", "zh-TW": "回到地球", ru: "Вернуться на Землю", hi: "पृथ्वी पर लौटो", id: "Kembali ke Bumi" },
